    // cast_byte(nupvals) → nupvals as u8 (already u8).
    // luaC_newobj → state.gc().new_obj(...) — in Phase A–C just Rc allocation.
    // gco2ccl → gc.cast_c_closure() — unnecessary in Rust, enum variant is the cast.
    //
