/// C: `LClosure *luaF_newLclosure(lua_State *L, int nupvals)`
pub(crate) fn new_lua_closure(
    state: &mut LuaState,
    nupvals: u8,
) -> GcRef<crate::state::LuaClosure> {
    // C: GCObject *o = luaC_newobj(L, LUA_VLCL, sizeLclosure(nupvals));
