///
/// C: `void luaF_initupvals(lua_State *L, LClosure *cl)`
pub(crate) fn init_upvals(state: &mut LuaState, cl: &GcRef<lua_types::LuaLClosure>) -> Result<(), LuaError> {
    // C: for (i = 0; i < cl->nupvalues; i++) {
