        loop {
            // C: buff[UTF8BUFFSZ - (n++)] = cast_char(0x80 | (x & 0x3f));
            buff[UTF8_BUF_SZ - n] = 0x80 | (x & 0x3f) as u8;
            n += 1;
            x >>= 6;
            mfb >>= 1;
            // C: while (x > mfb);
            if x <= mfb {
