pub fn hex_value(c: u8) -> u8 {
    // C: if (lisdigit(c)) return c - '0'; else return (ltolower(c) - 'a') + 10;
    if c.is_ascii_digit() {
        c - b'0'
    } else {
        c.to_ascii_lowercase() - b'a' + 10
    }
