    /// C: `gettotalbytes(g)` macro → `cast(lu_mem, (g)->totalbytes + (g)->GCdebt)`
    /// macros.tsv: `gettotalbytes → g.total_bytes()`
    pub fn total_bytes(&self) -> usize {
        // C: cast(lu_mem, (g)->totalbytes + (g)->GCdebt)
        (self.totalbytes + self.gc_debt) as usize
